1	//! Integration tests for COR24 emulator using as24-assembled .lgo files
2	
3	use cor24_emulator::assembler::Assembler;
4	use cor24_emulator::challenge::get_examples;
5	use cor24_emulator::cpu::executor::Executor;
6	use cor24_emulator::cpu::state::CpuState;
7	use cor24_emulator::loader::load_lgo;
8	
9	/// Load an LGO file, set PC, run for max_cycles
10	fn load_and_run(lgo_path: &str, entry: u32, max_cycles: u64) -> CpuState {
11	    let content = std::fs::read_to_string(lgo_path)
12	        .unwrap_or_else(|e| panic!("Cannot read {}: {}", lgo_path, e));
13	    let mut cpu = CpuState::new();
14	    cpu.io.uart_tx_busy_cycles = 0; // legacy: instant TX for .lgo programs that don't poll
15	    load_lgo(&content, &mut cpu).unwrap();
16	    cpu.pc = entry;
17	    let executor = Executor::new();
18	    executor.run(&mut cpu, max_cycles);
19	    cpu
20	}
21	
22	#[test]
23	fn test_led_on_lgo() {
24	    // The reference as24 .lgo writes 1 to LED register.
25	    // On hardware this is LED OFF (active-low: 1=OFF).
26	    // We preserve the .lgo as-is — it's from the reference toolchain.
27	    let cpu = load_and_run(
28	        concat!(env!("CARGO_MANIFEST_DIR"), "/tests/programs/led_on.lgo"),
29	        0,
30	        100,
31	    );
32	    assert_eq!(cpu.io.leds, 0x01, "LED register should be 0x01 (LED OFF, active-low)");
33	}
