169	/// Helper: assemble source, run, and return CPU state.
170	/// Uses instant UART TX (busy_cycles=0) for legacy tests that don't poll.
171	fn assemble_and_run(source: &str, max_cycles: u64) -> CpuState {
172	    let mut assembler = Assembler::new();
173	    let result = assembler.assemble(source);
174	    assert!(
175	        result.errors.is_empty(),
176	        "Assembly errors: {:?}",
177	        result.errors
178	    );
179	    let mut cpu = CpuState::new();
180	    cpu.io.uart_tx_busy_cycles = 0; // legacy: instant TX for tests that don't poll
181	    for (addr, byte) in result.bytes.iter().enumerate() {
182	        cpu.memory[addr] = *byte;
183	    }
184	    cpu.pc = 0;
185	    let executor = Executor::new();
186	    executor.run(&mut cpu, max_cycles);
187	    cpu
188	}
