190	/// All examples that terminate must reach halted state
191	#[test]
192	fn test_all_examples_halt() {
193	    // Examples that intentionally loop forever (no halt)
194	    let non_halting = ["Blink LED", "Button Echo", "Echo", "Loop Trace"];
195	    let examples = get_examples();
196	    for (name, _desc, source) in &examples {
197	        if non_halting.contains(&name.as_str()) {
198	            continue;
199	        }
200	        let mut assembler = Assembler::new();
201	        let result = assembler.assemble(source);
202	        if !result.errors.is_empty() {
203	            continue; // skip broken examples (tested elsewhere)
204	        }
205	        let mut cpu = CpuState::new();
206	        for (addr, byte) in result.bytes.iter().enumerate() {
207	            cpu.memory[addr] = *byte;
208	        }
209	        cpu.pc = 0;
210	        let executor = Executor::new();
211	        executor.run(&mut cpu, 500_000);
212	        assert!(
213	            cpu.halted,
214	            "Example '{}' did not halt within 500K cycles (PC=0x{:06X})",
215	            name, cpu.pc
216	        );
217	    }
218	}
219	
220	/// Self-branch halt detection works via single-step
221	#[test]
222	fn test_self_branch_halt_via_step() {
223	    let cpu = assemble_and_run("lc r0,1\nhalt:\nbra halt", 100);
224	    assert!(cpu.halted, "Self-branch should be detected as halt");
225	    assert_eq!(cpu.pc, 0x0002, "PC should point at the bra instruction");
226	}
227	
228	/// Step past halt: stepping a halted CPU should not change state
229	#[test]
230	fn test_step_halted_cpu_is_noop() {
231	    let mut cpu = assemble_and_run("halt:\nbra halt", 100);
232	    assert!(cpu.halted);
233	    let pc_before = cpu.pc;
234	    let cycles_before = cpu.cycles;
235	    let executor = Executor::new();
236	    executor.step(&mut cpu);
237	    assert!(cpu.halted, "CPU should remain halted after step");
238	    assert_eq!(cpu.pc, pc_before, "PC should not change");
239	    assert_eq!(cpu.cycles, cycles_before, "Cycles should not change");
240	}
