242	/// Memory Access example stores to non-adjacent blocks
243	#[test]
244	fn test_memory_access_non_adjacent() {
245	    let examples = get_examples();
246	    let mem = examples
247	        .iter()
248	        .find(|(name, _, _)| name == "Memory Access")
249	        .unwrap();
250	    let cpu = assemble_and_run(&mem.2, 1000);
251	    assert!(cpu.halted, "Memory Access should halt");
252	    // Check first block at 0x0100
253	    assert_eq!(cpu.read_byte(0x0100), 42, "Block 1: byte 0 should be 42");
254	    assert_eq!(cpu.read_byte(0x0101), 42, "Block 1: byte 1 should be 42");
255	    // Check second block at 0x0200
256	    assert_eq!(cpu.read_byte(0x0200), 200, "Block 2: byte 0 should be 200");
257	    // Gap between blocks should be zero
258	    assert_eq!(
259	        cpu.read_byte(0x0150),
260	        0,
261	        "Gap between blocks should be zero"
262	    );
263	}
