293	/// OOM example fills SRAM with 256-byte stride then halts
294	#[test]
295	fn test_oom_example() {
296	    let source = include_str!("../docs/examples/oom.s");
297	    let cpu = assemble_and_run(source, 500_000);
298	    assert!(cpu.halted, "OOM should halt when SRAM is exhausted");
299	    // First write at 0x0100 should be counter value 1
300	    assert_eq!(cpu.read_byte(0x0100), 1, "First store should be 1");
301	    // Second write at 0x0200 should be counter value 2
302	    assert_eq!(cpu.read_byte(0x0200), 2, "Second store should be 2");
303	    // Gap between writes should be zero
304	    assert_eq!(cpu.read_byte(0x0150), 0, "Gap should be zero");
305	}
306	
307	/// Stack overflow example fills EBR/Stack region then halts
308	#[test]
309	fn test_stack_overflow_example() {
310	    let source = include_str!("../docs/examples/stack_overflow.s");
311	    let cpu = assemble_and_run(source, 500_000);
312	    assert!(cpu.halted, "Stack overflow should halt when EBR exhausted");
313	    // SP should be at or below EBR base (0xFEE000)
314	    let sp = cpu.get_reg(4);
315	    assert!(
316	        sp <= 0xFEE000,
317	        "SP should be at or below EBR base, got 0x{:06X}",
318	        sp
319	    );
320	    // First push writes at 0xFEEBFD (SP-3 from initial 0xFEEC00)
321	    // Depth 0 is pushed, so word value is 0 — check second push pair (depth=1 at offset -12)
322	    assert_ne!(
323	        cpu.read_word(0xFEEBF1),
324	        0,
325	        "Stack should have recursion data"
326	    );
327	}
