329	/// Interrupt example: send UART bytes, verify ISR prints counter digits
330	#[test]
331	fn test_interrupt_example() {
332	    let source = include_str!("../docs/examples/interrupt.s");
333	    let mut assembler = Assembler::new();
334	    let result = assembler.assemble(source);
335	    assert!(
336	        result.errors.is_empty(),
337	        "Interrupt assembly errors: {:?}",
338	        result.errors
339	    );
340	
341	    let mut cpu = CpuState::new();
342	    for (addr, byte) in result.bytes.iter().enumerate() {
343	        cpu.memory[addr] = *byte;
344	    }
345	    cpu.pc = 0;
346	    let executor = Executor::new();
347	
348	    // Run some cycles to let main loop start counting
349	    executor.run(&mut cpu, 1000);
350	    assert!(!cpu.halted, "Main loop should keep running");
351	
352	    // Send a UART byte to trigger interrupt
353	    cpu.uart_send_rx(b'x');
354	    executor.run(&mut cpu, 1000);
355	
356	    // ISR should have printed a digit (0-9) to UART
357	    assert!(
358	        !cpu.io.uart_output.is_empty(),
359	        "ISR should have output a digit"
360	    );
361	    let first_char = cpu.io.uart_output.chars().next().unwrap();
362	    assert!(
363	        first_char.is_ascii_digit(),
364	        "Output should be ASCII digit, got '{}'",
365	        first_char
366	    );
367	
368	    // Send another byte, should get another digit
369	    cpu.uart_send_rx(b'y');
370	    executor.run(&mut cpu, 1000);
371	    assert_eq!(
372	        cpu.io.uart_output.len(),
373	        2,
374	        "Should have two digits after two interrupts"
375	    );
376	}
