378	/// Echo example: letters→uppercase, !→halt, others echo as-is
379	#[test]
380	fn test_echo_example() {
381	    let source = include_str!("../src/examples/assembler/echo.s");
382	    let mut assembler = Assembler::new();
383	    let result = assembler.assemble(source);
384	    assert!(
385	        result.errors.is_empty(),
386	        "Echo assembly errors: {:?}",
387	        result.errors
388	    );
389	
390	    let mut cpu = CpuState::new();
391	    for (addr, byte) in result.bytes.iter().enumerate() {
392	        cpu.memory[addr] = *byte;
393	    }
394	    cpu.pc = 0;
395	    let executor = Executor::new();
396	
397	    // Run to reach idle loop — prompt '?' should appear
398	    executor.run(&mut cpu, 100);
399	    assert_eq!(
400	        cpu.io.uart_output, "?",
401	        "Prompt '?' should appear on startup"
402	    );
403	
404	    // Send 'a' → uppercase 'A'
405	    cpu.uart_send_rx(b'a');
406	    executor.run(&mut cpu, 1000);
407	    assert_eq!(cpu.io.uart_output, "?A", "'a' -> 'A'");
408	
409	    // Send 'B' → already uppercase, echo 'B'
410	    cpu.uart_send_rx(b'B');
411	    executor.run(&mut cpu, 1000);
412	    assert_eq!(cpu.io.uart_output, "?AB", "'B' -> 'B'");
413	
414	    // Send '1' → not a letter, echo as-is
415	    cpu.uart_send_rx(b'1');
416	    executor.run(&mut cpu, 1000);
417	    assert_eq!(cpu.io.uart_output, "?AB1", "'1' -> '1'");
418	
419	    // Send '!' → halts
420	    cpu.uart_send_rx(b'!');
421	    executor.run(&mut cpu, 1000);
422	    assert!(cpu.halted, "Should halt on '!'");
423	}
