425	// ===== UART TX Discipline Tests =====
426	
427	/// Program that writes to UART WITHOUT polling TX busy.
428	/// With realistic timing (busy_cycles=10), characters should be dropped.
429	#[test]
430	fn test_uart_no_poll_drops_characters() {
431	    let source = r#"
432	        la      r1,-65280
433	        lc      r0,65
434	        sb      r0,0(r1)
435	        lc      r0,66
436	        sb      r0,0(r1)
437	        lc      r0,67
438	        sb      r0,0(r1)
439	halt:
440	        bra     halt
441	    "#;
442	    let mut assembler = Assembler::new();
443	    let result = assembler.assemble(source);
444	    assert!(result.errors.is_empty());
445	    let mut cpu = CpuState::new();
446	    // Realistic: 10 cycles busy after each write
447	    cpu.io.uart_tx_busy_cycles = 10;
448	    for (addr, byte) in result.bytes.iter().enumerate() {
449	        cpu.memory[addr] = *byte;
450	    }
451	    cpu.pc = 0;
452	    let executor = Executor::new();
453	    executor.run(&mut cpu, 10_000);
454	    // Only first character should get through — B and C written while busy
455	    assert_eq!(
456	        cpu.io.uart_output, "A",
457	        "Only 'A' should transmit; B,C dropped while busy"
458	    );
459	    assert_eq!(cpu.io.uart_tx_dropped, 2, "B and C should be dropped");
460	}
461	
462	/// Program that correctly polls TX busy before each write.
463	/// All characters should transmit even with realistic timing.
464	#[test]
465	fn test_uart_with_poll_all_characters() {
466	    let source = r#"
467	        la      r1,-65280
468	        lc      r0,65
469	.w1:
470	        lb      r2,1(r1)
471	        cls     r2,z
472	        brt     .w1
473	        sb      r0,0(r1)
474	        lc      r0,66
475	.w2:
476	        lb      r2,1(r1)
477	        cls     r2,z
478	        brt     .w2
479	        sb      r0,0(r1)
480	        lc      r0,67
481	.w3:
482	        lb      r2,1(r1)
483	        cls     r2,z
484	        brt     .w3
485	        sb      r0,0(r1)
486	halt:
487	        bra     halt
488	    "#;
489	    let mut assembler = Assembler::new();
490	    let result = assembler.assemble(source);
491	    assert!(result.errors.is_empty());
492	    let mut cpu = CpuState::new();
493	    cpu.io.uart_tx_busy_cycles = 10;
